create extension if not exists pgcrypto;
create extension if not exists citext;
create type public.app_role as enum ('applicant','reviewer','finance','program_admin','super_admin');
create type public.application_status as enum ('draft','applied','review_by_admin','additional_information_needed','approved','denied','withdrawn','archived');
create type public.deadline_kind as enum ('date','rolling','recurring','varies');
create type public.source_health as enum ('healthy','degraded','paused','failed');

create table public.profiles (id uuid primary key references auth.users on delete cascade, legal_name text, preferred_name text, primary_email citext unique, secondary_email citext, phone text, communication_consent boolean not null default false, institution text, degree_level text, major text, expected_graduation date, enrollment_status text, mailing_address jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.user_roles (user_id uuid references public.profiles on delete cascade, role app_role not null, program_id uuid, granted_by uuid references public.profiles, granted_at timestamptz not null default now(), primary key(user_id,role,program_id));
create table public.organizations (id uuid primary key default gen_random_uuid(), name text not null, kind text not null, created_at timestamptz not null default now());
create table public.programs (id uuid primary key default gen_random_uuid(), slug text unique not null, name text not null, description text, program_type text not null, active boolean not null default true, created_at timestamptz not null default now());
alter table public.user_roles add constraint user_roles_program_fk foreign key(program_id) references public.programs;
create table public.program_cycles (id uuid primary key default gen_random_uuid(), program_id uuid not null references public.programs, name text not null, opens_at timestamptz, closes_at timestamptz, award_config jsonb not null default '{}', status text not null default 'draft', unique(program_id,name));
create table public.form_versions (id uuid primary key default gen_random_uuid(), cycle_id uuid not null references public.program_cycles, version int not null, schema jsonb not null, published_at timestamptz, unique(cycle_id,version));
create table public.policy_versions (id uuid primary key default gen_random_uuid(), cycle_id uuid not null references public.program_cycles, version int not null, body text not null, published_at timestamptz, unique(cycle_id,version));
create table public.applications (id uuid primary key default gen_random_uuid(), applicant_id uuid not null references public.profiles, cycle_id uuid not null references public.program_cycles, form_version_id uuid not null references public.form_versions, status application_status not null default 'draft', source_system text, source_record_id text, original_submitted_at timestamptz, submitted_at timestamptz, archived_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(cycle_id,applicant_id), unique(source_system,source_record_id));
create table public.application_answers (application_id uuid references public.applications on delete cascade, question_key text not null, value jsonb not null, updated_at timestamptz not null default now(), primary key(application_id,question_key));
create table public.documents (id uuid primary key default gen_random_uuid(), application_id uuid not null references public.applications on delete cascade, owner_id uuid not null references public.profiles, storage_path text not null unique, kind text not null, filename text not null, content_type text not null, size_bytes bigint not null check(size_bytes>0), replaced_by uuid references public.documents, created_at timestamptz not null default now());
create table public.policy_acceptances (application_id uuid references public.applications, policy_version_id uuid references public.policy_versions, accepted_by uuid references public.profiles, accepted_at timestamptz not null default now(), ip_hash text, primary key(application_id,policy_version_id));
create table public.status_history (id bigint generated always as identity primary key, application_id uuid not null references public.applications, previous_status application_status, new_status application_status not null, actor_id uuid references public.profiles, reason text, applicant_note text, created_at timestamptz not null default now());
create table public.internal_notes (id uuid primary key default gen_random_uuid(), application_id uuid not null references public.applications, author_id uuid not null references public.profiles, body text not null, created_at timestamptz not null default now());
create table public.information_requests (id uuid primary key default gen_random_uuid(), application_id uuid not null references public.applications, requested_by uuid not null references public.profiles, item text not null, due_at timestamptz, response text, resolved_at timestamptz, created_at timestamptz not null default now());
create table public.review_assignments (id uuid primary key default gen_random_uuid(), application_id uuid not null references public.applications, reviewer_id uuid not null references public.profiles, conflict_disclosed boolean not null default false, assigned_at timestamptz not null default now(), unique(application_id,reviewer_id));
create table public.rubrics (id uuid primary key default gen_random_uuid(), cycle_id uuid not null references public.program_cycles, version int not null, criteria jsonb not null, unique(cycle_id,version));
create table public.reviews (id uuid primary key default gen_random_uuid(), assignment_id uuid not null unique references public.review_assignments, rubric_id uuid not null references public.rubrics, scores jsonb not null, notes text, locked_at timestamptz, reopened_by uuid references public.profiles, updated_at timestamptz not null default now());
create table public.decisions (id uuid primary key default gen_random_uuid(), application_id uuid not null unique references public.applications, decision application_status not null check(decision in ('approved','denied')), internal_reason text not null, applicant_explanation text, decided_by uuid not null references public.profiles, confirmed_at timestamptz not null);
create table public.awards (id uuid primary key default gen_random_uuid(), application_id uuid not null unique references public.applications, amount numeric(12,2), conditions text, acceptance_deadline date, accepted_at timestamptz, recipient jsonb, disbursement_status text, scheduled_date date, actual_date date, payment_reference text, created_at timestamptz not null default now());
create table public.import_jobs (id uuid primary key default gen_random_uuid(), program_id uuid not null references public.programs, file_hash text not null unique, mapping jsonb not null, status text not null default 'staged', created_by uuid not null references public.profiles, committed_at timestamptz, created_at timestamptz not null default now());
create table public.import_rows (id bigint generated always as identity primary key, job_id uuid not null references public.import_jobs on delete cascade, row_number int not null, raw_data jsonb not null, normalized_data jsonb, action text, errors jsonb not null default '[]', application_id uuid references public.applications, unique(job_id,row_number));
create table public.claim_invitations (id uuid primary key default gen_random_uuid(), application_id uuid not null references public.applications, email citext not null, token_hash text not null unique, expires_at timestamptz not null, sent_at timestamptz, claimed_at timestamptz, cancelled_at timestamptz, created_by uuid not null references public.profiles, created_at timestamptz not null default now());
create table public.email_templates (id uuid primary key default gen_random_uuid(), program_id uuid references public.programs, event_key text not null, subject text not null, body text not null, version int not null default 1, unique(program_id,event_key,version));
create table public.messages (id uuid primary key default gen_random_uuid(), application_id uuid references public.applications, template_id uuid references public.email_templates, recipient citext not null, idempotency_key text not null unique, provider_id text, status text not null default 'queued', created_at timestamptz not null default now());
create table public.external_sources (id uuid primary key default gen_random_uuid(), key text unique not null, name text not null, directory_url text not null, permission_status text not null, permission_notes text, active boolean not null default true, frequency_minutes int not null default 1440, parser_version text not null, health source_health not null default 'healthy', last_success_at timestamptz, last_error text, failure_count int not null default 0);
create table public.external_scholarships (id uuid primary key default gen_random_uuid(), slug text unique not null, title text not null, normalized_title text not null, sponsor text, summary text, amount_text text, amount_numeric numeric(12,2), deadline_kind deadline_kind not null, deadline date, original_url text not null, canonical_url text not null, eligibility jsonb not null default '{}', published_at timestamptz, featured boolean not null default false, archived_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.source_observations (id uuid primary key default gen_random_uuid(), source_id uuid not null references public.external_sources, scholarship_id uuid references public.external_scholarships, source_record_key text not null, source_page_url text not null, observed_data jsonb not null, first_seen_at timestamptz not null default now(), last_seen_at timestamptz not null default now(), unique(source_id,source_record_key));
create table public.importer_runs (id uuid primary key default gen_random_uuid(), source_id uuid not null references public.external_sources, status text not null, parser_version text not null, counts jsonb not null default '{}', error_safe text, started_at timestamptz not null default now(), completed_at timestamptz);
create table public.scholarship_exceptions (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.importer_runs, observation_id uuid references public.source_observations, kind text not null, detail_safe text not null, priority int not null default 1, resolved_at timestamptz, resolved_by uuid references public.profiles);
create table public.bookmarks (user_id uuid references public.profiles, scholarship_id uuid references public.external_scholarships, created_at timestamptz not null default now(), primary key(user_id,scholarship_id));
create table public.audit_events (id bigint generated always as identity primary key, actor_id uuid references public.profiles, action text not null, target_type text not null, target_id text not null, scope_id uuid, metadata_safe jsonb not null default '{}', created_at timestamptz not null default now());

create index applications_status_idx on public.applications(status,cycle_id); create index applications_applicant_idx on public.applications(applicant_id); create index scholarship_search_idx on public.external_scholarships using gin(to_tsvector('english',title||' '||coalesce(sponsor,'')||' '||coalesce(summary,''))); create index audit_target_idx on public.audit_events(target_type,target_id,created_at desc);
alter table public.profiles enable row level security; alter table public.applications enable row level security; alter table public.application_answers enable row level security; alter table public.documents enable row level security; alter table public.internal_notes enable row level security; alter table public.reviews enable row level security; alter table public.bookmarks enable row level security;
create function public.has_role(wanted app_role, wanted_program uuid default null) returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from user_roles where user_id=auth.uid() and role=wanted and (wanted_program is null or program_id is null or program_id=wanted_program)) $$;
create policy "profiles_self" on public.profiles for all using(id=auth.uid()) with check(id=auth.uid());
create policy "applications_owner_read" on public.applications for select using(applicant_id=auth.uid()); create policy "applications_owner_draft" on public.applications for update using(applicant_id=auth.uid() and status in ('draft','additional_information_needed')) with check(applicant_id=auth.uid());
create policy "answers_owner" on public.application_answers for all using(exists(select 1 from applications a where a.id=application_id and a.applicant_id=auth.uid())) with check(exists(select 1 from applications a where a.id=application_id and a.applicant_id=auth.uid() and a.status in ('draft','additional_information_needed')));
create policy "documents_owner" on public.documents for select using(owner_id=auth.uid()); create policy "notes_staff_only" on public.internal_notes for all using(has_role('reviewer') or has_role('program_admin') or has_role('super_admin')) with check(has_role('reviewer') or has_role('program_admin') or has_role('super_admin'));
create policy "reviews_assigned_or_admin" on public.reviews for select using(exists(select 1 from review_assignments ra where ra.id=assignment_id and ra.reviewer_id=auth.uid()) or has_role('program_admin') or has_role('super_admin'));
create policy "bookmarks_owner" on public.bookmarks for all using(user_id=auth.uid()) with check(user_id=auth.uid());

